    def __init__(self, max_calls, period):
        self.max_calls = max_calls
        self.period = period
        self.calls = 0
        self.window_start = _time.monotonic()

    def allow(self):
        elapsed = _time.monotonic() - self.window_start
        if elapsed >= self.period:
            self.window_start = _time.monotonic()
            self.calls = 0
        return self.calls < self.max_calls
